-- Auto-generated math standards for all 11 grades
-- Format: standart_kodu = Riy_<Roman>_<mezmun>.<std>, alt = Riy_<Roman>_<mezmun>.<std>.<alt>

TRUNCATE movcud_standartlar RESTART IDENTITY;
TRUNCATE yenilenmi_standartlar RESTART IDENTITY;


-- Copy all to yenilenmi_standartlar as 'movcud'
SELECT sinif, standart_kodu, mezmun_xetti, standart_metni, alt_standart_kodu, alt_standart_metni, 'movcud', standart_metni, bloom_seviyyesi
FROM movcud_standartlar ORDER BY sinif, standart_kodu, alt_standart_kodu;